// Pure expertise data + composer — safe to import anywhere.
// The optional Claude API call lives at the bottom behind a dynamic import so
// no server secret or SDK code ever reaches the client bundle.

/**
 * AI reply drafting + sales coaching expertise.
 *
 * Two engines:
 *  1. Built-in expertise engine — freight-forwarding playbooks and reply
 *     composition that work offline, free, deterministic.
 *  2. Optional Claude upgrade — when ANTHROPIC_API_KEY is configured, drafts
 *     are generated by Claude with the built-in guidance as grounding.
 * Either way: drafts only. A human always reviews before sending.
 */

// ---------------------------------------------------------------------------
// Intent detection
// ---------------------------------------------------------------------------

export type Intent =
  | "RATE_INQUIRY" | "SHIPMENT_STATUS" | "CUSTOMS" | "CLOSING_DATE" | "DOCUMENTS"
  | "COMPLAINT" | "DELAY" | "NEW_LEAD" | "PAYMENT" | "TRANSLOADING" | "GENERAL";

const INTENT_RULES: { intent: Intent; words: string[] }[] = [
  { intent: "COMPLAINT", words: ["complaint", "disappointed", "unacceptable", "angry", "poor service", "not happy", "frustrated", "terrible", "worst"] },
  { intent: "CUSTOMS", words: ["customs", "hs code", "k1", "k2", "k3", "k8", "zb", "duty", "tax", "permit", "kastam", "declaration", "clearance", "sirim", "maqis"] },
  { intent: "CLOSING_DATE", words: ["closing", "cut off", "cut-off", "cutoff", "closing date", "si cut", "vgm"] },
  { intent: "RATE_INQUIRY", words: ["rate", "quotation", "quote", "price", "pricing", "how much", "charges", "cost", "freight rate", "offer"] },
  { intent: "TRANSLOADING", words: ["transload", "trans-load", "cross dock", "crossdock", "reload"] },
  { intent: "DELAY", words: ["delay", "delayed", "postpone", "rolled", "roll over", "late arrival", "congestion", "eta change"] },
  { intent: "SHIPMENT_STATUS", words: ["status", "where is", "eta", "etd", "arrived", "tracking", "container", "vessel", "update on", "when will"] },
  { intent: "DOCUMENTS", words: ["document", "bl ", "bill of lading", "invoice copy", "packing list", "form e", "form d", "coo", "certificate", "delivery order", "d/o", "release the do", "collect the do"] },
  { intent: "PAYMENT", words: ["payment", "outstanding", "overdue", "credit", "invoice due", "statement", "soa"] },
  { intent: "NEW_LEAD", words: ["new shipment", "inquiry", "enquiry", "interested", "first time", "can you handle", "do you provide", "need shipping", "import from", "export to"] },
];

export function detectIntent(message: string): Intent {
  const m = ` ${message.toLowerCase()} `;
  for (const rule of INTENT_RULES) {
    if (rule.words.some((w) => m.includes(w))) return rule.intent;
  }
  return "GENERAL";
}

export const INTENT_LABELS: Record<Intent, string> = {
  RATE_INQUIRY: "💵 Rate / quotation inquiry", SHIPMENT_STATUS: "🚢 Shipment status", CUSTOMS: "🛃 Customs inquiry",
  CLOSING_DATE: "⏰ Closing date", DOCUMENTS: "📄 Documents", COMPLAINT: "😟 Complaint", DELAY: "⏳ Delay",
  NEW_LEAD: "✨ New lead", PAYMENT: "💳 Payment / collection", TRANSLOADING: "🔄 Transloading", GENERAL: "💬 General",
};

