const TONE_OPENERS: Record<Tone, string> = {
  PROFESSIONAL: "Dear {customerName},\n\n",
  FRIENDLY: "Hi {customerName},\n\nHope you're doing well! ",
  APOLOGETIC: "Dear {customerName},\n\nFirst of all, we sincerely apologise for the trouble. ",
};

/** Deterministic reply draft (no API needed). {placeholders} stay visible so nothing false is sent. */
export function composeReply(message: string, tone: Tone = "PROFESSIONAL"): { intent: Intent; draft: string; tips: string[] } {
  const intent = detectIntent(message);
  const draft = TONE_OPENERS[tone] + REPLY_BODIES[intent] + SIGN_OFF;
  const tips = REPLY_TIPS[intent] ?? [];
  return { intent, draft, tips };
}

